import AsyncStorage from '@react-native-async-storage/async-storage';

const BASE_URL = 'https://api.example.com';
const TOKEN_KEY = '@auth_token';
const REFRESH_TOKEN_KEY = '@refresh_token';

class ApiService {
  constructor() {
    this.baseURL = BASE_URL;
    this.token = null;
    this.refreshToken = null;
  }

  async init() {
    try {
      this.token = await AsyncStorage.getItem(TOKEN_KEY);
      this.refreshToken = await AsyncStorage.getItem(REFRESH_TOKEN_KEY);
    } catch (error) {
      console.error('Failed to load tokens:', error);
    }
  }

  async setTokens(token, refreshToken) {
    this.token = token;
    this.refreshToken = refreshToken;
    try {
      await AsyncStorage.setItem(TOKEN_KEY, token);
      if (refreshToken) {
        await AsyncStorage.setItem(REFRESH_TOKEN_KEY, refreshToken);
      }
    } catch (error) {
      console.error('Failed to save tokens:', error);
    }
  }

  async clearTokens() {
    this.token = null;
    this.refreshToken = null;
    try {
      await AsyncStorage.removeItem(TOKEN_KEY);
      await AsyncStorage.removeItem(REFRESH_TOKEN_KEY);
    } catch (error) {
      console.error('Failed to clear tokens:', error);
    }
  }

  getHeaders(includeAuth = true) {
    const headers = {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
    };

    if (includeAuth && this.token) {
      headers['Authorization'] = `Bearer ${this.token}`;
    }

    return headers;
  }

  async request(endpoint, options = {}) {
    const url = `${this.baseURL}${endpoint}`;
    const config = {
      ...options,
      headers: {
        ...this.getHeaders(options.includeAuth !== false),
        ...options.headers,
      },
    };

    try {
      const response = await fetch(url, config);
      
      if (response.status === 401 && this.refreshToken && options.retry !== false) {
        const refreshed = await this.refreshAccessToken();
        if (refreshed) {
          return this.request(endpoint, { ...options, retry: false });
        } else {
          await this.clearTokens();
          throw new Error('Session expired. Please login again.');
        }
      }

      const data = await response.json();

      if (!response.ok) {
        throw {
          status: response.status,
          message: data.message || data.error || 'Request failed',
          data: data,
        };
      }

      return data;
    } catch (error) {
      if (error.message === 'Network request failed') {
        throw new Error('Network error. Please check your connection.');
      }
      throw error;
    }
  }

  async get(endpoint, options = {}) {
    return this.request(endpoint, {
      ...options,
      method: 'GET',
    });
  }

  async post(endpoint, body, options = {}) {
    return this.request(endpoint, {
      ...options,
      method: 'POST',
      body: JSON.stringify(body),
    });
  }

  async put(endpoint, body, options = {}) {
    return this.request(endpoint, {
      ...options,
      method: 'PUT',
      body: JSON.stringify(body),
    });
  }

  async patch(endpoint, body, options = {}) {
    return this.request(endpoint, {
      ...options,
      method: 'PATCH',
      body: JSON.stringify(body),
    });
  }

  async delete(endpoint, options = {}) {
    return this.request(endpoint, {
      ...options,
      method: 'DELETE',
    });
  }

  async login(email, password) {
    const data = await this.post('/auth/login', { email, password }, { includeAuth: false });
    
    if (data.token) {
      await this.setTokens(data.token, data.refreshToken);
    }
    
    return data;
  }

  async register(userData) {
    const data = await this.post('/auth/register', userData, { includeAuth: false });
    
    if (data.token) {
      await this.setTokens(data.token, data.refreshToken);
    }
    
    return data;
  }

  async logout() {
    try {
      await this.post('/auth/logout', {});
    } catch (error) {
      console.error('Logout request failed:', error);
    } finally {
      await this.clearTokens();
    }
  }

  async refreshAccessToken() {
    if (!this.refreshToken) {
      return false;
    }

    try {
      const data = await this.post('/auth/refresh', 
        { refreshToken: this.refreshToken },
        { includeAuth: false, retry: false }
      );
      
      if (data.token) {
        await this.setTokens(data.token, data.refreshToken || this.refreshToken);
        return true;
      }
      
      return false;
    } catch (error) {
      console.error('Token refresh failed:', error);
      return false;
    }
  }

  async getUserProfile() {
    return this.get('/user/profile');
  }

  async updateUserProfile(profileData) {
    return this.put('/user/profile', profileData);
  }

  async updateUserAvatar(imageUri) {
    const formData = new FormData();
    formData.append('avatar', {
      uri: imageUri,
      type: 'image/jpeg',
      name: 'avatar.jpg',
    });

    const url = `${this.baseURL}/user/avatar`;
    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${this.token}`,
        'Content-Type': 'multipart/form-data',
      },
      body: formData,
    });

    const data = await response.json();

    if (!response.ok) {
      throw {
        status: response.status,
        message: data.message || 'Upload failed',
        data: data,
      };
    }

    return data;
  }

  async changePassword(currentPassword, newPassword) {
    return this.post('/user/change-password', {
      currentPassword,
      newPassword,
    });
  }

  async resetPassword(email) {
    return this.post('/auth/reset-password', { email }, { includeAuth: false });
  }

  async verifyResetToken(token, newPassword) {
    return this.post('/auth/verify-reset', { token, newPassword }, { includeAuth: false });
  }

  async fetchData(endpoint, params = {}) {
    const queryString = Object.keys(params)
      .map(key => `${encodeURIComponent(key)}=${encodeURIComponent(params[key])}`)
      .join('&');
    
    const url = queryString ? `${endpoint}?${queryString}` : endpoint;
    return this.get(url);
  }

  async createData(endpoint, data) {
    return this.post(endpoint, data);
  }

  async updateData(endpoint, id, data) {
    return this.put(`${endpoint}/${id}`, data);
  }

  async patchData(endpoint, id, data) {
    return this.patch(`${endpoint}/${id}`, data);
  }

  async deleteData(endpoint, id) {
    return this.delete(`${endpoint}/${id}`);
  }

  isAuthenticated() {
    return !!this.token;
  }

  getToken() {
    return this.token;
  }
}

const apiService = new ApiService();

export default apiService;

export const useApi = () => {
  return apiService;
};

export const initializeApi = async () => {
  await apiService.init();
};